static int gen(int x[], int i, int n, BoolFun f) {
    if (i == n) {
        return (*f)(x) ? 1 : 0;
    } else {
        int count = 0;
        x[i] = 0; count += gen(x, i+1, n, f);
        x[i] = 1; count += gen(x, i+1, n, f);
        return count;
